#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* getNode(Node** arr, int* cnt, int id) {
    for (int i = 0; i < *cnt; ++i) if (arr[i]->val == id) return arr[i];
    Node* nd = (Node*)malloc(sizeof(Node));
    nd->val = id;
    nd->left = nd->right = NULL;
    arr[(*cnt)++] = nd;
    return nd;
}

int minDepth(Node* root) {
    if (!root) return 0;
    Node* q[20000];
    int front = 0, rear = 0;
    q[rear++] = root;
    int depth = 0;
    while (front < rear) {
        int sz = rear - front;
        ++depth;
        for (int i = 0; i < sz; ++i) {
            Node* cur = q[front++];
            if (!cur->left && !cur->right) return depth;
            if (cur->left) q[rear++] = cur->left;
            if (cur->right) q[rear++] = cur->right;
        }
    }
    return depth;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node* nodes[20000];
        int nodeCnt = 0;
        int isChild[20000];
        memset(isChild, 0, sizeof(isChild));
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            Node* parent = getNode(nodes, &nodeCnt, p);
            Node* child  = getNode(nodes, &nodeCnt, c);
            if (dir == 'L') parent->left = child; else parent->right = child;
            // mark child id
            for (int j = 0; j < nodeCnt; ++j) if (nodes[j]->val == c) { isChild[j] = 1; break; }
        }
        // find root (node not marked as child)
        Node* root = NULL;
        for (int i = 0; i < nodeCnt; ++i) if (!isChild[i]) { root = nodes[i]; break; }
        if (!root && N==1) { // single node case, create it
            root = getNode(nodes, &nodeCnt, 1);
        }
        printf("%d\n", minDepth(root));
        // free memory (optional for contest)
        for (int i = 0; i < nodeCnt; ++i) free(nodes[i]);
    }
    return 0;
}

