#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* left = nullptr;
    Node* right = nullptr;
    Node(int v): val(v) {}
};

int minDepth(Node* root) {
    if (!root) return 0;
    queue<Node*> q;
    q.push(root);
    int depth = 0;
    while (!q.empty()) {
        ++depth;
        int sz = q.size();
        while (sz--) {
            Node* cur = q.front(); q.pop();
            if (!cur->left && !cur->right) return depth;
            if (cur->left) q.push(cur->left);
            if (cur->right) q.push(cur->right);
        }
    }
    return depth;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        unordered_map<int, Node*> mp;
        unordered_set<int> childSet;
        for (int i=0;i<N-1;++i) {
            int p,c; char dir; cin>>p>>c>>dir;
            if (!mp.count(p)) mp[p]=new Node(p);
            if (!mp.count(c)) mp[c]=new Node(c);
            if (dir=='L') mp[p]->left = mp[c]; else mp[p]->right = mp[c];
            childSet.insert(c);
        }
        Node* root = nullptr;
        if (N==1) {
            // single node, its id can be any number; we take the first key if exists else create 1
            int id = 1;
            root = new Node(id);
        } else {
            for (auto &kv: mp) if (!childSet.count(kv.first)) { root = kv.second; break; }
        }
        cout << minDepth(root) << '\n';
        // cleanup
        for (auto &kv: mp) delete kv.second;
    }
    return 0;
}

