import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    static int minDepth(Node root) {
        if (root == null) return 0;
        Queue<Node> q = new ArrayDeque<>();
        q.add(root);
        int depth = 0;
        while (!q.isEmpty()) {
            depth++;
            int sz = q.size();
            for (int i = 0; i < sz; i++) {
                Node cur = q.poll();
                if (cur.left == null && cur.right == null) return depth;
                if (cur.left != null) q.add(cur.left);
                if (cur.right != null) q.add(cur.right);
            }
        }
        return depth;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                map.putIfAbsent(p, new Node(p));
                map.putIfAbsent(c, new Node(c));
                Node parent = map.get(p);
                Node child = map.get(c);
                if (dir == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
            }
            Node root = null;
            if (N == 1) {
                // single node, id can be any; use 1
                root = new Node(1);
            } else {
                for (Map.Entry<Integer, Node> e : map.entrySet()) {
                    if (!childSet.contains(e.getKey())) { root = e.getValue(); break; }
                }
            }
            sb.append(minDepth(root)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

