import sys
from collections import deque

def min_depth(root):
    if not root:
        return 0
    q = deque([root])
    depth = 0
    while q:
        depth += 1
        for _ in range(len(q)):
            node = q.popleft()
            if not node['left'] and not node['right']:
                return depth
            if node['left']:
                q.append(node['left'])
            if node['right']:
                q.append(node['right'])
    return depth

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        N = int(data[idx].strip()); idx += 1
        nodes = {}
        children = set()
        for _ in range(N-1):
            pi, ci, Ri = data[idx].split(); idx += 1
            pi = int(pi); ci = int(ci)
            if pi not in nodes:
                nodes[pi] = {'val': pi, 'left': None, 'right': None}
            if ci not in nodes:
                nodes[ci] = {'val': ci, 'left': None, 'right': None}
            if Ri == 'L':
                nodes[pi]['left'] = nodes[ci]
            else:
                nodes[pi]['right'] = nodes[ci]
            children.add(ci)
        if N == 1:
            # single node, pick any id (use first key if exists else 1)
            root = {'val': 1, 'left': None, 'right': None}
        else:
            root = None
            for nid, node in nodes.items():
                if nid not in children:
                    root = node
                    break
        out_lines.append(str(min_depth(root)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

