const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
    const N = parseInt(input[idx++]);
    const nodes = new Map(); // id -> node object
    const childSet = new Set();
    function getNode(id) {
        if (!nodes.has(id)) nodes.set(id, {val: id, left: null, right: null});
        return nodes.get(id);
    }
    for (let i = 0; i < N - 1; i++) {
        const [pStr, cStr, dir] = input[idx++].trim().split(' ');
        const p = parseInt(pStr), c = parseInt(cStr);
        const parent = getNode(p);
        const child = getNode(c);
        if (dir === 'L') parent.left = child; else parent.right = child;
        childSet.add(c);
    }
    let root = null;
    if (N === 1) {
        root = {val: 1, left: null, right: null};
    } else {
        for (let [id, node] of nodes) {
            if (!childSet.has(id)) { root = node; break; }
        }
    }
    // BFS to find minimum depth
    const queue = [];
    if (root) queue.push(root);
    let depth = 0;
    while (queue.length) {
        depth++;
        const size = queue.length;
        for (let i = 0; i < size; i++) {
            const cur = queue.shift();
            if (!cur.left && !cur.right) {
                outputs.push(String(depth));
                queue.length = 0; // break outer while
                break;
            }
            if (cur.left) queue.push(cur.left);
            if (cur.right) queue.push(cur.right);
        }
    }
    if (N === 0) outputs.push('0'); // safety, though N>=1 per constraints
}
